import { describe, it, expect, vi, beforeEach } from 'vitest';

// Assuming useAuth is exported from './auth'
import { useAuth } from './auth';

// Mock any external dependencies (e.g., localStorage, fetch)
vi.mock('localStorage', () => ({
  getItem: vi.fn(),
  setItem: vi.fn(),
  removeItem: vi.fn(),
}));

describe('useAuth', () => {
  let auth: ReturnType<typeof useAuth>;

  beforeEach(() => {
    auth = useAuth();
  });

  it('should handle happy path for login and logout', () => {
    // Simulate a successful login
    auth.login('testuser', 'password123');
    expect(auth.isAuthenticated()).toBeTruthy();
    // Ensure localStorage was set
    expect(vi.fn()).toHaveBeenCalledWith('userToken', expect.any(String));

    // Now logout
    auth.logout();
    expect(auth.isAuthenticated()).toBeFalsy();
    // Ensure localStorage was removed
    expect(vi.fn()).toHaveBeenCalledWith('userToken');
  });

  it('should handle edge case when trying to logout without being logged in', () => {
    // Ensure initially not authenticated
    expect(auth.isAuthenticated()).toBeFalsy();
    // Call logout; should not throw error
    expect(() => auth.logout()).not.toThrow();
    // isAuthenticated remains false
    expect(auth.isAuthenticated()).toBeFalsy();
  });

  it('should handle null/empty inputs for login', () => {
    // Pass null or empty string
    expect(() => auth.login(null as unknown as string, '' as unknown as string)).toThrow();
    // isAuthenticated should still be false
    expect(auth.isAuthenticated()).toBeFalsy();
  });
});